import { describe, it, expect } from 'vitest';
import {
  validateUserExists,
  validateEmailUniqueness,
  validateEmailNotInUse,
} from '../../src/validators/user.validator.js';
import type { User } from '../../src/models/user.js';

const makeUser = (overrides: Partial<User> = {}): User => ({
  id: 'user-0001',
  name: 'Alice',
  email: 'alice@example.com',
  role: 'member',
  createdAt: new Date(),
  updatedAt: new Date(),
  ...overrides,
});

describe('user.validator', () => {
  // ---------------------------------------------------------------------------
  // validateUserExists
  // ---------------------------------------------------------------------------

  describe('validateUserExists', () => {
    it('should not throw when user exists', () => {
      const user = makeUser();
      expect(() => validateUserExists(user, 'user-0001')).not.toThrow();
    });

    it('should throw when user is undefined', () => {
      expect(() => validateUserExists(undefined, 'user-0001')).toThrow(
        'User not found: user-0001',
      );
    });

    it('should include the user ID in the error message', () => {
      expect(() => validateUserExists(undefined, 'user-9999')).toThrow(
        'user-9999',
      );
    });
  });

  // ---------------------------------------------------------------------------
  // validateEmailUniqueness
  // ---------------------------------------------------------------------------

  describe('validateEmailUniqueness', () => {
    it('should not throw when no existing user has the email', () => {
      expect(() =>
        validateEmailUniqueness(undefined, 'new@example.com'),
      ).not.toThrow();
    });

    it('should throw when a user with the email already exists', () => {
      const existing = makeUser({ email: 'taken@example.com' });
      expect(() =>
        validateEmailUniqueness(existing, 'taken@example.com'),
      ).toThrow('User with email taken@example.com already exists');
    });

    it('should include the email in the error message', () => {
      const existing = makeUser();
      expect(() =>
        validateEmailUniqueness(existing, 'alice@example.com'),
      ).toThrow('alice@example.com');
    });
  });

  // ---------------------------------------------------------------------------
  // validateEmailNotInUse
  // ---------------------------------------------------------------------------

  describe('validateEmailNotInUse', () => {
    it('should not throw when no user holds the email', () => {
      expect(() =>
        validateEmailNotInUse(undefined, 'free@example.com'),
      ).not.toThrow();
    });

    it('should throw when the email is already in use', () => {
      const existing = makeUser({ email: 'taken@example.com' });
      expect(() =>
        validateEmailNotInUse(existing, 'taken@example.com'),
      ).toThrow('Email taken@example.com is already in use');
    });

    it('should include the email in the error message', () => {
      const existing = makeUser();
      expect(() =>
        validateEmailNotInUse(existing, 'alice@example.com'),
      ).toThrow('alice@example.com');
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validateOrderExists,
  validateOrderHasItems,
  isValidStatusTransition,
  validateStatusTransition,
} from '../../src/validators/order.validator.js';
import type { Order, OrderItem, OrderStatus } from '../../src/models/order.js';

const makeOrder = (overrides: Partial<Order> = {}): Order => ({
  id: 'order-0001',
  userId: 'user-0001',
  items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
  total: 20,
  status: 'pending',
  createdAt: new Date(),
  updatedAt: new Date(),
  ...overrides,
});

const makeItem = (overrides: Partial<OrderItem> = {}): OrderItem => ({
  productId: 'p1',
  name: 'Widget',
  quantity: 1,
  unitPrice: 10,
  ...overrides,
});

describe('order.validator', () => {
  // ---------------------------------------------------------------------------
  // validateOrderExists
  // ---------------------------------------------------------------------------

  describe('validateOrderExists', () => {
    it('should not throw when order exists', () => {
      const order = makeOrder();
      expect(() => validateOrderExists(order, 'order-0001')).not.toThrow();
    });

    it('should throw when order is undefined', () => {
      expect(() => validateOrderExists(undefined, 'order-0001')).toThrow(
        'Order not found: order-0001',
      );
    });

    it('should include the order ID in the error message', () => {
      expect(() => validateOrderExists(undefined, 'order-9999')).toThrow(
        'order-9999',
      );
    });
  });

  // ---------------------------------------------------------------------------
  // validateOrderHasItems
  // ---------------------------------------------------------------------------

  describe('validateOrderHasItems', () => {
    it('should not throw when items array is non-empty', () => {
      expect(() => validateOrderHasItems([makeItem()])).not.toThrow();
    });

    it('should not throw when there are multiple items', () => {
      expect(() =>
        validateOrderHasItems([makeItem(), makeItem({ productId: 'p2' })]),
      ).not.toThrow();
    });

    it('should throw when items array is empty', () => {
      expect(() => validateOrderHasItems([])).toThrow(
        'Order must have at least one item',
      );
    });
  });

  // ---------------------------------------------------------------------------
  // isValidStatusTransition
  // ---------------------------------------------------------------------------

  describe('isValidStatusTransition', () => {
    it('should allow pending -> confirmed', () => {
      expect(isValidStatusTransition('pending', 'confirmed')).toBe(true);
    });

    it('should allow pending -> cancelled', () => {
      expect(isValidStatusTransition('pending', 'cancelled')).toBe(true);
    });

    it('should allow confirmed -> shipped', () => {
      expect(isValidStatusTransition('confirmed', 'shipped')).toBe(true);
    });

    it('should allow confirmed -> cancelled', () => {
      expect(isValidStatusTransition('confirmed', 'cancelled')).toBe(true);
    });

    it('should allow shipped -> delivered', () => {
      expect(isValidStatusTransition('shipped', 'delivered')).toBe(true);
    });

    it('should reject pending -> delivered', () => {
      expect(isValidStatusTransition('pending', 'delivered')).toBe(false);
    });

    it('should reject pending -> shipped', () => {
      expect(isValidStatusTransition('pending', 'shipped')).toBe(false);
    });

    it('should reject delivered -> any', () => {
      const statuses: OrderStatus[] = ['pending', 'confirmed', 'shipped', 'delivered', 'cancelled'];
      for (const s of statuses) {
        expect(isValidStatusTransition('delivered', s)).toBe(false);
      }
    });

    it('should reject cancelled -> any', () => {
      const statuses: OrderStatus[] = ['pending', 'confirmed', 'shipped', 'delivered', 'cancelled'];
      for (const s of statuses) {
        expect(isValidStatusTransition('cancelled', s)).toBe(false);
      }
    });

    it('should reject shipped -> confirmed', () => {
      expect(isValidStatusTransition('shipped', 'confirmed')).toBe(false);
    });
  });

  // ---------------------------------------------------------------------------
  // validateStatusTransition
  // ---------------------------------------------------------------------------

  describe('validateStatusTransition', () => {
    it('should not throw for valid transition', () => {
      expect(() => validateStatusTransition('pending', 'confirmed')).not.toThrow();
    });

    it('should throw for invalid transition', () => {
      expect(() => validateStatusTransition('pending', 'delivered')).toThrow(
        'Invalid status transition: pending -> delivered',
      );
    });

    it('should throw for transitions from terminal states', () => {
      expect(() => validateStatusTransition('delivered', 'confirmed')).toThrow(
        'Invalid status transition: delivered -> confirmed',
      );
      expect(() => validateStatusTransition('cancelled', 'confirmed')).toThrow(
        'Invalid status transition: cancelled -> confirmed',
      );
    });

    it('should include from and to statuses in error message', () => {
      expect(() => validateStatusTransition('shipped', 'pending')).toThrow(
        'shipped -> pending',
      );
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validatePreferencesNotExist,
  validatePreferencesExist,
} from '../../src/validators/preferences.validator.js';
import type { UserPreferences } from '../../src/models/user-preferences.js';
import { ALL_NOTIFICATION_CATEGORIES } from '../../src/models/user-preferences.js';

const makePreferences = (overrides: Partial<UserPreferences> = {}): UserPreferences => ({
  id: 'user-0001',
  userId: 'user-0001',
  email: {
    enabled: true,
    frequency: 'immediate',
    subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
  },
  createdAt: new Date(),
  updatedAt: new Date(),
  ...overrides,
});

describe('preferences.validator', () => {
  // ---------------------------------------------------------------------------
  // validatePreferencesNotExist
  // ---------------------------------------------------------------------------

  describe('validatePreferencesNotExist', () => {
    it('should not throw when no preferences exist', () => {
      expect(() =>
        validatePreferencesNotExist(undefined, 'user-0001'),
      ).not.toThrow();
    });

    it('should throw when preferences already exist', () => {
      const existing = makePreferences();
      expect(() =>
        validatePreferencesNotExist(existing, 'user-0001'),
      ).toThrow('Preferences already exist for user: user-0001');
    });

    it('should include the user ID in the error message', () => {
      const existing = makePreferences({ userId: 'user-9999' });
      expect(() =>
        validatePreferencesNotExist(existing, 'user-9999'),
      ).toThrow('user-9999');
    });
  });

  // ---------------------------------------------------------------------------
  // validatePreferencesExist
  // ---------------------------------------------------------------------------

  describe('validatePreferencesExist', () => {
    it('should not throw when preferences exist', () => {
      const existing = makePreferences();
      expect(() =>
        validatePreferencesExist(existing, 'user-0001'),
      ).not.toThrow();
    });

    it('should throw when preferences are undefined', () => {
      expect(() =>
        validatePreferencesExist(undefined, 'user-0001'),
      ).toThrow('Preferences not found for user: user-0001');
    });

    it('should include the user ID in the error message', () => {
      expect(() =>
        validatePreferencesExist(undefined, 'user-9999'),
      ).toThrow('user-9999');
    });
  });
});
